using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned metadata for: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): check-without-throwing ---
// With the default reflection resolver every type resolves, so use a
// source-gen-only context that only knows about Person.
var limited = new JsonSerializerOptions { TypeInfoResolver = SmallContext.Default };

if (limited.TryGetTypeInfo<Person>(out var info))
    Console.WriteLine($"TryGet Person: found ({info!.Type.Name})");
else
    Console.WriteLine("TryGet Person: NOT found");

if (limited.TryGetTypeInfo<Order>(out var orderInfo))
    Console.WriteLine($"TryGet Order: found ({orderInfo!.Type.Name})");
else
    Console.WriteLine("TryGet Order: NOT found  (no exception thrown)");

// --- Types ---
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

// Source-gen context that only registers Person
[JsonSerializable(typeof(Person))]
public partial class SmallContext : JsonSerializerContext;

